targets.expr:
count(
  vmware_vm_power_state{
    vmware_cluster_name=~"$cluster",
    vm_name!~"^ubuntu.*"
  } == 0
) OR vector(0)

sum by (vmware_cluster_name)(
  vmware_host_cpu_usagemhz_average{vmware_cluster_name=~"$cluster"}
  unless on (host_name) (vmware_host_maintenance_mode == 1)
) * 100
/
sum by (vmware_cluster_name)(
  vmware_host_cpu_max{vmware_cluster_name=~"$cluster"}
  unless on (host_name) (vmware_host_maintenance_mode == 1)
)

sum(
  vmware_host_memory_usage{vmware_cluster_name=~"$cluster"}
  unless on (host_name) (vmware_host_maintenance_mode == 1)
) * 100
/
sum(
  vmware_host_memory_max{vmware_cluster_name=~"$cluster"}
  unless on (host_name) (vmware_host_maintenance_mode == 1)
)

100 *
sum by (dc_name, vmware_cluster_name) (
  (vmware_vm_memory_max or vmware_vm_memory_size_mb)
  * on (vm_name) group_left () (vmware_vm_power_state == 1)
  * on (host_name) group_left (dc_name, vmware_cluster_name)
    vmware_host_hardware_info{dc_name=~"$DC", vmware_cluster_name=~"$cluster"}
)
/ sum by (dc_name, vmware_cluster_name) (
  (
    (vmware_host_memory_max or vmware_host_memory_total or vmware_host_memory_capacity)
    unless on (host_name) (vmware_host_maintenance_mode == 1)
  )
  * on (host_name) group_left (dc_name, vmware_cluster_name)
    vmware_host_hardware_info{dc_name=~"$DC", vmware_cluster_name=~"$cluster"}
)

100 *
sum by (dc_name, vmware_cluster_name) (
  (vmware_vm_num_cpu or vmware_vm_cpu_count or vmware_vm_vcpu or vmware_vm_vcpu_count)
  * on (vm_name) group_left () (vmware_vm_power_state == 1)
  * on (host_name) group_left (dc_name, vmware_cluster_name)
    vmware_host_hardware_info{dc_name=~"$DC", vmware_cluster_name=~"$cluster"}
)
/ sum by (dc_name, vmware_cluster_name) (
  (
    vmware_host_num_cpu
    unless on (host_name) (vmware_host_maintenance_mode == 1)
  )
  * on (host_name) group_left (dc_name, vmware_cluster_name)
    vmware_host_hardware_info{dc_name=~"$DC", vmware_cluster_name=~"$cluster"}
)

(
  sum by (host_name, vmware_cluster_name, dc_name)(vmware_host_maintenance_mode{vmware_cluster_name=~"$cluster"})
  +
  on (host_name) group_left(hardware_cpu_model, hardware_model)
  0 * vmware_host_hardware_info{vmware_cluster_name=~"$cluster"}
)
+
on (host_name) group_left(build, version)
0 * vmware_host_product_info{vmware_cluster_name=~"$cluster"}
